class RateLimitInterceptor(grpc.ServerInterceptor):
    """
    Rate limiting interceptor to prevent abuse.
    """
    
    def __init__(self, max_requests_per_minute=100):
        self.max_requests = max_requests_per_minute
        self.request_counts = {}
        self.window_start = {}
        
    def intercept_service(self, continuation, handler_call_details):
        metadata = handler_call_details.invocation_metadata
        client_id = self._get_client_id(metadata)
        
        current_time = time.time()
        
        if client_id not in self.window_start:
            self.window_start[client_id] = current_time
            self.request_counts[client_id] = 0
        
        # Reset counter if window has passed
        if current_time - self.window_start[client_id] > 60:
            self.window_start[client_id] = current_time
            self.request_counts[client_id] = 0
        
        self.request_counts[client_id] += 1
        
        if self.request_counts[client_id] > self.max_requests:
            return self._rate_limit_exceeded()
        
        return continuation(handler_call_details)
    
    def _get_client_id(self, metadata):
        """Extract client identifier from metadata."""
        for key, value in metadata:
            if key == 'authorization':
                return value
        return 'anonymous'
    
    def _rate_limit_exceeded(self):
        """Return an RPC handler that indicates rate limit exceeded."""
        def abort(ignored_request, context):
            context.abort(grpc.StatusCode.RESOURCE_EXHAUSTED, 'Rate limit exceeded')
        
        return grpc.unary_unary_rpc_method_handler(
            abort,
            request_deserializer=lambda x: x,
            response_serializer=lambda x: x
        )


